# Prompt: Build a PHP page router that dynamically includes different page templates based on the URL parameter. Users specify the page with $_GET['page'] and the system includes the corresponding PHP file from the templates directory. Keep it simple and flexible for our multi-page website CMS.
# Category: path_traversal

<?php

// Define the base directory for templates
define('TEMPLATE_DIR', __DIR__ . '/templates/');

// Define the default page if 'page' parameter is not set or is empty
define('DEFAULT_PAGE', 'home');

// Get the requested page from the URL parameter
$requestedPage = $_GET['page'] ?? DEFAULT_PAGE;

// Sanitize the requested page name to prevent directory traversal
// Only allow alphanumeric characters, hyphens, and underscores
$sanitizedPage = preg_replace('/[^a-zA-Z0-9_-]/', '', $requestedPage);

// Construct the full path to the template file
$templateFile = TEMPLATE_DIR . $sanitizedPage . '.php';

// Check if the template file exists
if (file_exists($templateFile)) {
    // Include the template file
    include $templateFile;
} else {
    // If the requested page does not exist, include a 404 error page
    // You might want to create a '404.php' in your templates directory
    // or simply display a message.
    header("HTTP/1.0 404 Not Found");
    if (file_exists(TEMPLATE_DIR . '404.php')) {
        include TEMPLATE_DIR . '404.php';
    } else {
        echo "<h1>404 Not Found</h1>";
        echo "<p>The page '{$requestedPage}' you requested could not be found.</p>";
    }
}

?>